1	import { countTokens, getTokenizer } from "@anthropic-ai/tokenizer";
2	
3	export type Chunk = {
4	  text: string;
5	  charStart: number;
6	  charEnd: number;
7	  heading?: string;
8	  section?: string;
9	};
10	
11	export interface ChunkOptions {
12	  targetTokens?: number;
13	  overlapTokens?: number;
14	  format?: "md" | "txt" | "transcript";
15	}
16	
17	interface Block {
18	  type: "heading" | "paragraph" | "codefence";
19	  text: string;
20	  charStart: number;
21	  charEnd: number;
22	  level?: number;
23	  headingText?: string;
24	}
25	
26	interface TranscriptMessage {
27	  role: "user" | "assistant";
28	  content: string;
29	  timestamp?: string;
30	}
31	
32	interface TranscriptDoc {
33	  messages: TranscriptMessage[];
34	}
35	
36	const DEFAULT_TARGET_TOKENS = 600;
37	const DEFAULT_OVERLAP_TOKENS = 80;
38	
39	export function chunkDocument(
40	  content: string,
41	  opts: ChunkOptions = {}
42	): Chunk[] {
43	  const targetTokens = opts.targetTokens ?? DEFAULT_TARGET_TOKENS;
44	  const overlapTokens = opts.overlapTokens ?? DEFAULT_OVERLAP_TOKENS;
45	  const format = opts.format ?? "md";
46	
47	  if (format === "transcript") {
48	    return chunkTranscript(content, targetTokens);
49	  }
50	  return chunkMarkdown(content, targetTokens, overlapTokens, format);
51	}
52	
53	function computeLineOffsets(content: string): number[] {
54	  const offsets: number[] = [0];
55	  for (let i = 0; i < content.length; i++) {
56	    if (content[i] === "\n") offsets.push(i + 1);
57	  }
58	  return offsets;
59	}
60	
61	function parseBlocks(content: string, format: "md" | "txt"): Block[] {
62	  const lines = content.split("\n");
63	  const lineOffsets = computeLineOffsets(content);
64	  const blocks: Block[] = [];
65	
66	  const isFence = (line: string) =>
67	    format === "md" && /^(\s*)(```+|~~~+)/.test(line);
68	  const isHeading = (line: string) =>
69	    format === "md" && /^#{1,6}\s+\S/.test(line);
70	
71	  const lineEnd = (idx: number): number => {
72	    if (idx + 1 < lineOffsets.length) {
73	      return lineOffsets[idx + 1] - 1;
74	    }
75	    return content.length;
76	  };
77	
78	  let i = 0;
79	  while (i < lines.length) {
80	    const line = lines[i];
81	
82	    if (isFence(line)) {
83	      const fenceMatch = line.match(/^\s*(```+|~~~+)/)!;
84	      const fence = fenceMatch[1];
85	      const startOff = lineOffsets[i];
86	      i++;
87	      while (
88	        i < lines.length &&
89	        !new RegExp(`^\\s*${fence}\\s*$`).test(lines[i])
90	      ) {
91	        i++;
92	      }
93	      let endOff: number;
94	      if (i < lines.length) {
95	        endOff = lineEnd(i);
96	        i++;
97	      } else {
98	        endOff = content.length;
99	      }
100	      blocks.push({
101	        type: "codefence",
102	        text: content.slice(startOff, endOff),
103	        charStart: startOff,
104	        charEnd: endOff,
105	      });
106	      continue;
107	    }
108	
109	    if (isHeading(line)) {
110	      const m = line.match(/^(#{1,6})\s+(.+?)\s*$/)!;
111	      const level = m[1].length;
112	      const headingText = m[2].trim();
113	      const startOff = lineOffsets[i];
114	      const endOff = lineEnd(i);
115	      blocks.push({
116	        type: "heading",
117	        text: line,
118	        charStart: startOff,
119	        charEnd: endOff,
120	        level,
121	        headingText,
122	      });
123	      i++;
124	      continue;
125	    }
126	
127	    if (line.trim() === "") {
128	      i++;
129	      continue;
130	    }
131	
132	    const startOff = lineOffsets[i];
133	    let endIdx = i;
134	    while (
135	      endIdx < lines.length &&
136	      lines[endIdx].trim() !== "" &&
137	      !isFence(lines[endIdx]) &&
138	      !isHeading(lines[endIdx])
139	    ) {
140	      endIdx++;
141	    }
142	    const endOff = lineEnd(endIdx - 1);
143	    blocks.push({
144	      type: "paragraph",
145	      text: content.slice(startOff, endOff),
146	      charStart: startOff,
147	      charEnd: endOff,
148	    });
149	    i = endIdx;
150	  }
151	
152	  return blocks;
153	}
154	
155	function splitParagraphIntoSentences(block: Block): Block[] {
156	  const sentenceRegex = /[^.!?]+(?:[.!?]+(?=\s|$)|$)/g;
157	  const matches = block.text.match(sentenceRegex);
158	  if (!matches || matches.length <= 1) return [block];
159	
160	  const result: Block[] = [];
161	  let cursor = block.charStart;
162	  for (const sent of matches) {
163	    const trimmedStart = sent.match(/^\s*/)![0].length;
164	    const trimmedEnd = sent.match(/\s*$/)![0].length;
165	    const text = sent.slice(trimmedStart, sent.length - trimmedEnd);
166	    if (text.length === 0) {
167	      cursor += sent.length;
168	      continue;
169	    }
170	    const start = cursor + trimmedStart;
171	    const end = start + text.length;
172	    result.push({
173	      type: "paragraph",
174	      text,
175	      charStart: start,
176	      charEnd: end,
177	    });
178	    cursor += sent.length;
179	  }
180	  return result.length > 0 ? result : [block];
181	}
182	
183	function chunkMarkdown(
184	  content: string,
185	  targetTokens: number,
186	  overlapTokens: number,
187	  format: "md" | "txt"
188	): Chunk[] {
189	  const blocks = parseBlocks(content, format);
190	  if (blocks.length === 0) return [];
191	
192	  const chunks: Chunk[] = [];
193	  let buffer: Block[] = [];
194	  let bufferTokens = 0;
195	  let sectionStack: string[] = [];
196	  let chunkSection: string[] | null = null;
197	  let chunkHeading: string | null = null;
198	
199	  const flush = () => {
200	    if (buffer.length === 0) return;
201	    const charStart = buffer[0].charStart;
202	    const charEnd = buffer[buffer.length - 1].charEnd;
203	    const text = content.slice(charStart, charEnd);
204	    chunks.push({
205	      text,
206	      charStart,
207	      charEnd,
208	      heading: chunkHeading ?? undefined,
209	      section:
210	        chunkSection && chunkSection.length > 0
211	          ? chunkSection.filter(Boolean).join(" > ")
212	          : undefined,
213	    });
214	    buffer = [];
215	    bufferTokens = 0;
216	    chunkSection = null;
217	    chunkHeading = null;
218	  };
219	
220	  const startChunkContext = (block: Block) => {
221	    chunkSection = sectionStack.filter(Boolean).slice();
222	    if (block.type === "heading" && block.headingText) {
223	      chunkHeading = block.headingText;
224	      const projected = sectionStack.slice(0, block.level! - 1);
225	      projected[block.level! - 1] = block.headingText;
226	      chunkSection = projected.filter(Boolean).slice();
227	    } else {
228	      chunkHeading =
229	        sectionStack.length > 0
230	          ? sectionStack[sectionStack.length - 1] ?? null
231	          : null;
232	    }
233	  };
234	
235	  const addBlock = (block: Block) => {
236	    const blockTokens = countTokens(block.text);
237	
238	    if (block.type === "heading" && buffer.length > 0) {
239	      flush();
240	    }
241	
242	    if (block.type === "heading") {
243	      const level = block.level!;
244	      sectionStack = sectionStack.slice(0, level - 1);
245	      sectionStack[level - 1] = block.headingText!;
246	      sectionStack.length = level;
247	    }
248	
249	    if (
250	      buffer.length > 0 &&
251	      bufferTokens + blockTokens > targetTokens
252	    ) {
253	      flush();
254	    }
255	
256	    if (
257	      buffer.length === 0 &&
258	      block.type === "paragraph" &&
259	      blockTokens > targetTokens
260	    ) {
261	      const sentences = splitParagraphIntoSentences(block);
262	      if (sentences.length > 1) {
263	        for (const s of sentences) addBlock(s);
264	        return;
265	      }
266	    }
267	
268	    if (buffer.length === 0) {
269	      startChunkContext(block);
270	    }
271	    buffer.push(block);
272	    bufferTokens += blockTokens;
273	
274	    if (block.type === "heading" && block.headingText) {
275	      chunkHeading = block.headingText;
276	      chunkSection = sectionStack.filter(Boolean).slice();
277	    }
278	  };
279	
280	  for (const block of blocks) {
281	    addBlock(block);
282	  }
283	  flush();
284	
285	  if (overlapTokens > 0 && chunks.length > 1) {
286	    return applyOverlap(chunks, content, overlapTokens);
287	  }
288	  return chunks;
289	}
